function.arguments:
{"cmd":"SUBJECT=$(openssl x509 -in /app/ssl/server.crt -noout -subject | sed 's/^subject=//')
NOT_BEFORE=$(openssl x509 -in /app/ssl/server.crt -noout -startdate | sed 's/^notBefore=//')
NOT_AFTER=$(openssl x509 -in /app/ssl/server.crt -noout -enddate | sed 's/^notAfter=//')
FINGERPRINT=$(openssl x509 -in /app/ssl/server.crt -noout -fingerprint -sha256 | sed 's/sha256 Fingerprint=//' | sed 's/SHA256 Fingerprint=//')

cat > /app/ssl/verification.txt << EOF
Subject: ${SUBJECT}
Validity Start: ${NOT_BEFORE}
Validity End: ${NOT_AFTER}
SHA-256 Fingerprint: ${FINGERPRINT}
EOF

echo "Verification file created"
cat /app/ssl/verification.txt"}
